// Change Order Sync: syncs CO from GHL to ClickUp
const GHL_TOKEN = '{{ghl_token}}';
const CLICKUP_TOKEN = '{{clickup_token}}';
const CO_LIST_ID = '{{clickup_list_pending_cos}}';
const GHL_BASE = 'https://services.leadconnectorhq.com';
const CU_BASE = 'https://api.clickup.com/api/v2';
const GHL_HEADERS = { 'Authorization': `Bearer ${GHL_TOKEN}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };
const CU_HEADERS = { 'Authorization': CLICKUP_TOKEN, 'Content-Type': 'application/json' };

const body = $input.first().json;
const oppId = body.opportunity_id || body.id;
const coAmount = body.change_order_amount || 0;
const coReason = body.reason || 'No reason provided';

if (!oppId) return [{ json: { status: 'error', message: 'No opportunity ID' } }];

// Get opportunity name
const resp = await fetch(`${GHL_BASE}/opportunities/${oppId}`, { headers: GHL_HEADERS });
const opp = await resp.json();

// Create CO task in ClickUp
const task = await fetch(`${CU_BASE}/list/${CO_LIST_ID}/task`, {
  method: 'POST',
  headers: CU_HEADERS,
  body: JSON.stringify({
    name: `CO: ${opp.name || oppId} — $${coAmount}`,
    description: `**Change Order**\nOpportunity: ${opp.name}\nAmount: $${coAmount}\nReason: ${coReason}\nGHL ID: ${oppId}`,
    status: 'Open',
    priority: 2
  })
});
const taskData = await task.json();

// Add note to GHL opportunity
await fetch(`${GHL_BASE}/opportunities/${oppId}/notes`, {
  method: 'POST',
  headers: GHL_HEADERS,
  body: JSON.stringify({ body: `Change Order: $${coAmount} — ${coReason}. ClickUp task: ${taskData.id}` })
});

return [{ json: { status: 'ok', opportunity_id: oppId, co_amount: coAmount, clickup_task_id: taskData.id } }];
